"""

import random
import sys
from pathlib import Path

_tests_dir = Path(__file__).parent.parent / "public"
if str(_tests_dir) not in sys.path:
    sys.path.insert(0, str(_tests_dir))

from fixtures import make_test_result, approx_equal

TEST_POINTS = {
    "test_markov_chain_exact_probabilities_custom": 1,
    "test_markov_chain_minimal_data": 1,
    "test_markov_chain_insufficient_data": 1,
    "test_markov_chain_order2_probabilities": 1,
    "test_predict_length_custom": 1,
    "test_predict_deterministic_custom": 1,
    "test_predict_unknown_state_custom": 1,
    "test_predict_zero_predictions": 1,
    "test_predict_returns_list": 1,
    "test_predict_order2_sliding_window": 1,
    "test_mse_zero_custom": 1,
    "test_mse_simple_custom": 1,
    "test_mse_negative": 1,
    "test_mse_single_element": 1,
    "test_mse_floats": 1,
    "test_run_experiment_returns_float_custom": 1,
    "test_run_experiment_nonnegative": 1,
    "test_run_experiment_many_trials": 1,
}


# ============================================================================
# Markov Chain Tests
# ============================================================================

def test_markov_chain_exact_probabilities_custom(module):
    """Test markov_chain exact probability values."""
    data = [0, 1, 0, 1, 0, 2]
    chain = module.markov_chain(data, 1)

    # (0,) -> 1 appears twice, 2 appears once => P(1)=2/3, P(2)=1/3
    key = (0,)
    if key not in chain:
        return make_test_result(False, f"key {key} in chain", "key not found")

    if not approx_equal(chain[key].get(1, 0), 2/3, tolerance=0.001):
        return make_test_result(False, 2/3, chain[key].get(1, 0))

    if not approx_equal(chain[key].get(2, 0), 1/3, tolerance=0.001):
        return make_test_result(False, 1/3, chain[key].get(2, 0))

    return make_test_result(True, "exact probabilities", "exact probabilities")

test_markov_chain_exact_probabilities_custom.input_description = "data=[0,1,0,1,0,2], order=1"


def test_markov_chain_minimal_data(module):
    """Test markov_chain with minimal data (order+1 elements)."""
    data = [1, 2]
    chain = module.markov_chain(data, 1)

    if not isinstance(chain, dict):
        return make_test_result(False, "dict", type(chain).__name__)

    key = (1,)
    if key not in chain:
        return make_test_result(False, f"key {key} in chain", "key not found")

    if not approx_equal(chain[key].get(2, 0), 1.0):
        return make_test_result(False, 1.0, chain[key].get(2, 0))

    return make_test_result(True, "minimal data", "minimal data")

test_markov_chain_minimal_data.input_description = "data=[1,2], order=1"


def test_markov_chain_insufficient_data(module):
    """Test markov_chain with insufficient data returns empty dict."""
    data = [1]
    chain = module.markov_chain(data, 1)

    if not isinstance(chain, dict):
        return make_test_result(False, "dict", type(chain).__name__)

    if len(chain) != 0:
        return make_test_result(False, "empty dict", str(chain))

    return make_test_result(True, "empty dict", "empty dict")

test_markov_chain_insufficient_data.input_description = "data=[1], order=1"


def test_markov_chain_order2_probabilities(module):
    """Test order 2 markov chain probabilities."""
    data = [1, 2, 1, 2, 1, 2, 3]
    chain = module.markov_chain(data, 2)

    key = (1, 2)
    if key not in chain:
        return make_test_result(False, f"key {key} in chain", "key not found")

    transitions = chain[key]
    # (1,2) -> 1 appears twice, (1,2) -> 3 appears once => P(1)=2/3, P(3)=1/3
    if not approx_equal(transitions.get(1, 0), 2/3, tolerance=0.001):
        return make_test_result(False, 2/3, transitions.get(1, 0))

    return make_test_result(True, "order 2 probabilities", "order 2 probabilities")

test_markov_chain_order2_probabilities.input_description = "data=[1,2,1,2,1,2,3], order=2"


# ============================================================================
# Predict Tests
# ============================================================================

def test_predict_length_custom(module):
    """Test predict returns correct length list."""
    model = {(0,): {1: 1.0}}
    result = module.predict(model, [0], 5)

    if not isinstance(result, list):
        return make_test_result(False, "list", type(result).__name__)

    if len(result) != 5:
        return make_test_result(False, 5, len(result))

    return make_test_result(True, "length 5", "length 5")

test_predict_length_custom.input_description = "model={(0,): {1: 1.0}}, last=[0], num=5"


def test_predict_deterministic_custom(module):
    """Test predict with deterministic model."""
    model = {(0,): {1: 1.0}, (1,): {0: 1.0}}
    result = module.predict(model, [0], 6)

    expected = [1, 0, 1, 0, 1, 0]
    if result != expected:
        return make_test_result(False, expected, result)

    return make_test_result(True, expected, result)

test_predict_deterministic_custom.input_description = "model={(0,): {1: 1.0}, (1,): {0: 1.0}}, last=[0], num=6"


def test_predict_unknown_state_custom(module):
    """Test predict with unknown state returns values 0-3."""
    model = {}  # Empty model
    random.seed(42)
    result = module.predict(model, [0], 10)

    if len(result) != 10:
        return make_test_result(False, 10, len(result))

    # All values should be 0-3
    for val in result:
        if val not in [0, 1, 2, 3]:
            return make_test_result(False, "values in 0-3", val)

    return make_test_result(True, "values in 0-3", "values in 0-3")

test_predict_unknown_state_custom.input_description = "empty model, last=[0], num=10"


