    return make_test_result(True, "list", "list")

test_predict_returns_list.input_description = "model={(0,): {1: 1.0}}, last=[0], num=1"


def test_predict_order2_sliding_window(module):
    """Test predict with order 2 uses sliding window correctly."""
    model = {(0, 1): {2: 1.0}, (1, 2): {3: 1.0}, (2, 3): {0: 1.0}, (3, 0): {1: 1.0}}
    result = module.predict(model, [0, 1], 4)

    expected = [2, 3, 0, 1]
    if result != expected:
        return make_test_result(False, expected, result)

    return make_test_result(True, expected, result)

test_predict_order2_sliding_window.input_description = "deterministic order-2 cycle model"


# ============================================================================
# MSE Tests
# ============================================================================

def test_mse_zero_custom(module):
    """Test mse with identical lists."""
    result = module.mse([1, 2, 3], [1, 2, 3])

    if not approx_equal(result, 0.0):
        return make_test_result(False, 0.0, result)

    return make_test_result(True, 0.0, result)

test_mse_zero_custom.input_description = "result=[1,2,3], expected=[1,2,3]"


def test_mse_simple_custom(module):
    """Test mse with simple values."""
    result = module.mse([1, 2, 3], [4, 5, 6])

    # ((1-4)^2 + (2-5)^2 + (3-6)^2) / 3 = (9+9+9)/3 = 9.0
    if not approx_equal(result, 9.0):
        return make_test_result(False, 9.0, result)

    return make_test_result(True, 9.0, result)

test_mse_simple_custom.input_description = "result=[1,2,3], expected=[4,5,6]"


def test_mse_negative(module):
    """Test mse with negative differences."""
    result = module.mse([5, 5], [3, 7])

    # ((5-3)^2 + (5-7)^2) / 2 = (4+4)/2 = 4.0
    if not approx_equal(result, 4.0):
        return make_test_result(False, 4.0, result)

    return make_test_result(True, 4.0, result)

test_mse_negative.input_description = "result=[5,5], expected=[3,7]"


def test_mse_single_element(module):
    """Test mse with single element."""
    result = module.mse([3], [5])

    # (3-5)^2 / 1 = 4.0
    if not approx_equal(result, 4.0):
        return make_test_result(False, 4.0, result)

    return make_test_result(True, 4.0, result)

test_mse_single_element.input_description = "result=[3], expected=[5]"


def test_mse_floats(module):
    """Test mse with float values."""
    result = module.mse([1.5, 2.5], [2.5, 3.5])

    # ((1.5-2.5)^2 + (2.5-3.5)^2) / 2 = (1+1)/2 = 1.0
    if not approx_equal(result, 1.0):
        return make_test_result(False, 1.0, result)

    return make_test_result(True, 1.0, result)

test_mse_floats.input_description = "result=[1.5,2.5], expected=[2.5,3.5]"


